class Solution {
    public int[] separateDigits(int[] nums) {
        int[] result = new int[nums.length * nums[0].toString().length()];
        int index = 0;
        for (int num : nums) {
            String str = Integer.toString(num);
            for (char c : str.toCharArray()) {
                result[index++] = c - '0';
            }
        }
        return result;
    }
}
